class TestFindRootOp:
    """Test find_root_op() priority logic matching _getRootOp from space.py."""

    def test_priority1_linalg_with_reduction(self):
        """Priority 1: Last linalg op (reversed) with a reduction axis."""
        ops = [
            ["linalg.generic-0", [64, 32], ["parallel", "parallel"], [2, 0]],
            ["linalg.matmul-0", [64, 64, 32], ["parallel", "parallel", "reduction"], [2, 1]],
        ]
        assert find_root_op(ops) == 1

    def test_priority1_picks_last_with_reduction(self):
        """When multiple linalg ops have reduction, pick the last one (reversed scan)."""
        ops = [
            ["linalg.matmul-0", [64, 64, 32], ["parallel", "parallel", "reduction"], [2, 1]],
            ["linalg.generic-0", [64, 32], ["parallel", "parallel"], [2, 0]],
            ["linalg.conv-0", [1, 8, 8, 16, 3], ["parallel", "parallel", "parallel", "parallel", "reduction"], [3, 1]],
        ]
        assert find_root_op(ops) == 2

    def test_priority2_linalg_without_reduction(self):
        """Priority 2: Last linalg op (any) when no linalg op has reduction."""
        ops = [
            ["linalg.generic-0", [64, 32], ["parallel", "parallel"], [2, 0]],
            ["linalg.generic-1", [128], ["parallel"], [1, 0]],
        ]
        assert find_root_op(ops) == 1

    def test_priority3_tensor_pad_pack_unpack(self):
        """Priority 3: Last tensor.pad/pack/unpack when no linalg ops exist."""
        ops = [
            ["tensor.pack-0", [64, 32], ["parallel", "parallel"], [1, 0]],
            ["tensor.unpack-0", [128], ["parallel"], [1, 0]],
        ]
        assert find_root_op(ops) == 1

    def test_single_op(self):
        """Single op should always be root."""
        ops = [["linalg.generic-0", [512, 32], ["parallel", "parallel"], [2, 0]]]
        assert find_root_op(ops) == 0

    def test_linalg_with_reduction_preferred_over_tensor(self):
        """Linalg with reduction is preferred over tensor.pack."""
        ops = [
            ["tensor.pack-0", [64, 32], ["parallel", "parallel"], [1, 0]],
            ["linalg.matmul-0", [64, 64, 32], ["parallel", "parallel", "reduction"], [2, 1]],
        ]
        assert find_root_op(ops) == 1

    def test_empty_ops_returns_none(self):
        """Empty ops list should return None."""
        assert find_root_op([]) is None


